'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import {
  ArrowLeft,
  ArrowRight,
  Building2,
  MapPin,
  Ruler,
  Home,
  DollarSign,
  Image as ImageIcon,
  Upload,
  Check,
  Calendar,
  User,
  Briefcase,
  X,
  Save,
  Loader2,
  AlertCircle,
  Sparkles,
  BedDouble,
  Bath,
  Car,
  Maximize,
} from 'lucide-react'

type Step = 1 | 2 | 3 | 4

interface FormData {
  // Step 1: Básico
  name: string
  type: string
  location: string
  address: string
  developer: string

  // Step 2: Características
  area: string
  bedrooms: string
  bathrooms: string
  parking: string
  floor: string
  features: string[]

  // Step 3: Valores
  priceMin: string
  priceMax: string
  pricePerSqm: string
  totalUnits: string
  availableUnits: string
  deliveryDate: string

  // Step 4: Mídia
  images: File[]
  logo: File | null
}

// ⚠️ Dados reais Recife
const tiposImovel = [
  'Apartamento',
  'Casa',
  'Cobertura',
  'Studio',
  'Loft',
  'Terreno',
  'Comercial',
]

const localizacoes = [
  'Boa Viagem',
  'Pina',
  'Piedade',
  'Setúbal',
  'Candeias',
  'Imbiribeira',
  'Ipsep',
  'Recife Antigo',
]

const construtoras = [
  'Grupo IMI',
  'Moura Dubeux',
  'Queiroz Galvão',
  'Cyrela',
  'MRV',
  'Rossi',
  'Tenda',
  'Outra',
]

const featuresOptions = [
  'Piscina',
  'Academia',
  'Salão de festas',
  'Churrasqueira',
  'Playground',
  'Quadra esportiva',
  'Sauna',
  'Espaço gourmet',
  'Coworking',
  'Pet place',
  'Brinquedoteca',
  'Salão de jogos',
  'Cinema',
  'Spa',
  'Jardim',
  'Portaria 24h',
  'Segurança',
  'Elevador',
]

export default function NovoImovelPage() {
  const router = useRouter()
  const [currentStep, setCurrentStep] = useState<Step>(1)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [errors, setErrors] = useState<Record<string, string>>({})

  const [formData, setFormData] = useState<FormData>({
    name: '',
    type: '',
    location: '',
    address: '',
    developer: '',
    area: '',
    bedrooms: '',
    bathrooms: '',
    parking: '',
    floor: '',
    features: [],
    priceMin: '',
    priceMax: '',
    pricePerSqm: '',
    totalUnits: '',
    availableUnits: '',
    deliveryDate: '',
    images: [],
    logo: null,
  })

  const handleChange = (field: keyof FormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }))
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: '' }))
    }
  }

  const toggleFeature = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }))
  }

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || [])
    setFormData(prev => ({ ...prev, images: [...prev.images, ...files] }))
  }

  const removeImage = (index: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images.filter((_, i) => i !== index)
    }))
  }

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      setFormData(prev => ({ ...prev, logo: file }))
    }
  }

  const validateStep = (step: Step): boolean => {
    const newErrors: Record<string, string> = {}

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Nome é obrigatório'
      if (!formData.type) newErrors.type = 'Tipo é obrigatório'
      if (!formData.location) newErrors.location = 'Localização é obrigatória'
      if (!formData.address.trim()) newErrors.address = 'Endereço é obrigatório'
      if (!formData.developer) newErrors.developer = 'Construtora é obrigatória'
    }

    if (step === 2) {
      if (!formData.area) newErrors.area = 'Área é obrigatória'
      if (!formData.bedrooms) newErrors.bedrooms = 'Quartos é obrigatório'
      if (!formData.bathrooms) newErrors.bathrooms = 'Banheiros é obrigatório'
    }

    if (step === 3) {
      if (!formData.priceMin) newErrors.priceMin = 'Preço mínimo é obrigatório'
      if (!formData.priceMax) newErrors.priceMax = 'Preço máximo é obrigatório'
      if (!formData.totalUnits) newErrors.totalUnits = 'Total de unidades é obrigatório'
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep((prev) => Math.min(4, prev + 1) as Step)
    }
  }

  const handlePrev = () => {
    setCurrentStep((prev) => Math.max(1, prev - 1) as Step)
  }

  const handleSubmit = async () => {
    if (!validateStep(currentStep)) return

    setIsSubmitting(true)

    // TODO: Upload images to Supabase Storage
    // TODO: Save to Supabase database
    await new Promise(resolve => setTimeout(resolve, 2000))

    alert('Empreendimento cadastrado com sucesso!')
    router.push('/backoffice/imoveis')
  }

  const formatCurrency = (value: string) => {
    const numbers = value.replace(/\D/g, '')
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
      minimumFractionDigits: 0,
    }).format(Number(numbers))
  }

  const steps = [
    { number: 1, label: 'Básico', icon: Building2 },
    { number: 2, label: 'Características', icon: Home },
    { number: 3, label: 'Valores', icon: DollarSign },
    { number: 4, label: 'Mídia', icon: ImageIcon },
  ]

  const progress = (currentStep / 4) * 100

  return (
    <div className="space-y-6">
