'use client'

import { useState, useEffect } from 'react'
import {
    Bell,
    X,
    Users,
    Building2,
    FileText,
    MessageSquare,
    AlertCircle
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import Link from 'next/link'
import { toast } from 'sonner'

const supabase = createClient()

interface Notification {
    id: string
    user_id: string
    type: 'lead' | 'development' | 'evaluation' | 'consultation' | 'system' | 'comment'
    title: string
    message: string | null
    data: any
    read: boolean
    read_at: string | null
    created_at: string
}

export default function NotificationCenter() {
    const [isOpen, setIsOpen] = useState(false)
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [loading, setLoading] = useState(false)

    useEffect(() => {
        loadNotifications()
        const unsubscribe = subscribeToNotifications()
        return () => {
            if (unsubscribe) unsubscribe()
        }
    }, [])

    const loadNotifications = async () => {
        setLoading(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            const { data, error } = await supabase
                .from('notifications')
                .select('*')
                .eq('user_id', user.id)
                .order('created_at', { ascending: false })
                .limit(20)

            if (error) throw error

            setNotifications(data || [])
            setUnreadCount(data?.filter((n: Notification) => !n.read).length || 0)

        } catch (error) {
            console.error('Erro ao carregar notificações:', error)
        } finally {
            setLoading(false)
        }
    }

    const subscribeToNotifications = () => {
        const subscription = supabase
            .channel('notifications-channel')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'notifications'
                },
                (payload) => {
                    const newNotification = payload.new as Notification

                    setNotifications(prev => [newNotification, ...prev])
                    setUnreadCount(prev => prev + 1)

                    // Toast notification
                    toast(newNotification.title, {
                        description: newNotification.message,
                        action: {
                            label: 'Ver',
                            onClick: () => handleNotificationClick(newNotification)
                        }
                    })

                    // Browser notification
                    if ('Notification' in window && Notification.permission === 'granted') {
                        new Notification(newNotification.title, {
                            body: newNotification.message || undefined,
                            icon: '/icon-192.png',
                            badge: '/icon-192.png'
                        })
                    }
                }
            )
            .subscribe()

        return () => {
            subscription.unsubscribe()
        }
    }

    const markAsRead = async (notificationId: string) => {
        try {
            const { error } = await supabase
                .from('notifications')
                .update({ read: true, read_at: new Date().toISOString() })
                .eq('id', notificationId)

            if (error) throw error

            setNotifications(prev =>
                prev.map(n => n.id === notificationId ? { ...n, read: true } : n)
            )
            setUnreadCount(prev => Math.max(0, prev - 1))

        } catch (error) {
            console.error('Erro ao marcar como lida:', error)
        }
    }

    const markAllAsRead = async () => {
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            const { error } = await supabase
                .from('notifications')
                .update({ read: true, read_at: new Date().toISOString() })
                .eq('user_id', user.id)
                .eq('read', false)

            if (error) throw error

            setNotifications(prev => prev.map(n => ({ ...n, read: true })))
            setUnreadCount(0)
            toast.success('Todas notificações marcadas como lidas')

        } catch (error) {
            console.error('Erro ao marcar todas como lidas:', error)
        }
    }

    const deleteNotification = async (notificationId: string) => {
        try {
            const { error } = await supabase
                .from('notifications')
                .delete()
                .eq('id', notificationId)

            if (error) throw error

            setNotifications(prev => prev.filter(n => n.id !== notificationId))
            toast.success('Notificação removida')

        } catch (error) {
            console.error('Erro ao deletar notificação:', error)
        }
    }

    const handleNotificationClick = (notification: Notification) => {
        markAsRead(notification.id)
        setIsOpen(false)

        // Navigate based on type
        if (notification.data?.url) {
            window.location.href = notification.data.url
        }
    }

    const getNotificationIcon = (type: string) => {
        const icons: Record<string, any> = {
            lead: Users,
            development: Building2,
            evaluation: FileText,
            consultation: MessageSquare,
            system: AlertCircle,
            comment: MessageSquare
        }
        return icons[type] || Bell
    }

    const getNotificationColor = (type: string) => {
        const colors: Record<string, string> = {
            lead: 'bg-purple-50 text-purple-600',
            development: 'bg-blue-50 text-blue-600',
            evaluation: 'bg-pink-50 text-pink-600',
            consultation: 'bg-orange-50 text-orange-600',
            system: 'bg-gray-50 text-gray-600',
            comment: 'bg-green-50 text-green-600'
        }
        return colors[type] || 'bg-gray-50 text-gray-600'
    }

    const requestNotificationPermission = async () => {
        if ('Notification' in window && Notification.permission === 'default') {
            const permission = await Notification.requestPermission()
            if (permission === 'granted') {
                toast.success('Notificações ativadas!')
            }
        }
    }

    // Handle permission request on mount only once? 
    // User code had this separate useEffect.
    useEffect(() => {
        requestNotificationPermission()
    }, [])

    return (
        <>
            {/* Bell Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="relative w-10 h-10 rounded-xl hover:bg-imi-100 flex items-center justify-center transition-colors focus:outline-none focus:ring-2 focus:ring-accent-500/20"
            >
                <Bell size={20} className="text-imi-700" />
                {unreadCount > 0 && (
                    <div className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center animate-pulse shadow-sm">
                        {unreadCount > 9 ? '9+' : unreadCount}
                    </div>
                )}
            </button>

            {/* Notification Panel */}
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <div
                        className="fixed inset-0 z-40 bg-transparent"
                        onClick={() => setIsOpen(false)}
                    />

                    {/* Panel */}
                    <div className="absolute top-12 right-0 md:fixed md:top-20 md:right-4 w-96 max-h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-2xl border border-imi-100 z-50 flex flex-col animate-in slide-in-from-top-4 duration-200 origin-top-right">
                        {/* Header */}
                        <div className="flex items-center justify-between p-6 border-b border-imi-100 sticky top-0 bg-white/95 backdrop-blur-sm z-10 rounded-t-2xl">
                            <div>
                                <h3 className="font-bold text-imi-900 text-lg">Notificações</h3>
                                {unreadCount > 0 && (
                                    <p className="text-xs text-imi-500 mt-0.5 font-medium">
                                        {unreadCount} não {unreadCount === 1 ? 'lida' : 'lidas'}
                                    </p>
                                )}
                            </div>
                            {notifications.length > 0 && (
                                <button
                                    onClick={markAllAsRead}
                                    className="text-sm font-medium text-accent-600 hover:text-accent-700 px-3 py-1.5 rounded-lg hover:bg-accent-50 transition-colors"
                                >
                                    Marcar todas
                                </button>
                            )}
                        </div>

                        {/* List */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar">
                            {loading ? (
                                <div className="p-12 text-center">
                                    <div className="w-8 h-8 border-4 border-accent-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                                    <p className="text-imi-600 text-sm">Carregando...</p>
                                </div>
                            ) : notifications.length === 0 ? (
                                <div className="p-12 text-center">
                                    <div className="w-16 h-16 bg-imi-50 rounded-full flex items-center justify-center mx-auto mb-4">
                                        <Bell size={24} className="text-imi-300" />
                                    </div>
                                    <p className="font-medium text-imi-900 mb-1">Nenhuma notificação</p>
                                    <p className="text-sm text-imi-500">Você está em dia!</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-imi-50">
                                    {notifications.map((notification) => {
                                        const Icon = getNotificationIcon(notification.type)
                                        const colorClass = getNotificationColor(notification.type)

                                        return (
                                            <div
                                                key={notification.id}
                                                className={`p-4 hover:bg-imi-50 transition-colors cursor-pointer group relative ${!notification.read ? 'bg-accent-50/20' : ''
                                                    }`}
                                                onClick={() => handleNotificationClick(notification)}
                                            >
                                                <div className="flex gap-3">
                                                    <div className={`w-10 h-10 rounded-xl ${colorClass} flex items-center justify-center flex-shrink-0 mt-0.5`}>
                                                        <Icon size={18} />
                                                    </div>

                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex items-start justify-between gap-2 mb-0.5">
                                                            <h4 className={`font-medium text-sm ${!notification.read ? 'text-imi-900' : 'text-imi-700'}`}>
                                                                {notification.title}
                                                            </h4>
                                                            {!notification.read && (
                                                                <div className="w-2 h-2 rounded-full bg-accent-500 flex-shrink-0 mt-1.5" />
                                                            )}
                                                        </div>

                                                        {notification.message && (
                                                            <p className="text-sm text-imi-600 line-clamp-2 mb-2 leading-relaxed">
                                                                {notification.message}
                                                            </p>
                                                        )}

                                                        <div className="flex items-center justify-between">
                                                            <span className="text-xs text-imi-400 font-medium">
                                                                {formatDistanceToNow(new Date(notification.created_at), {
                                                                    addSuffix: true,
                                                                    locale: ptBR
                                                                })}
                                                            </span>

                                                            <button
                                                                onClick={(e) => {
                                                                    e.stopPropagation()
                                                                    deleteNotification(notification.id)
                                                                }}
                                                                className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-red-50 rounded-lg text-red-500 transition-all hover:text-red-700"
                                                                title="Remover notificação"
                                                            >
                                                                <X size={14} />
                                                            </button>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        )
                                    })}
                                </div>
                            )}
                        </div>

                        {/* Footer */}
                        {notifications.length > 0 && (
                            <div className="p-4 border-t border-imi-100 bg-imi-50 rounded-b-2xl">
                                <Link
                                    href="/backoffice/notificacoes"
                                    onClick={() => setIsOpen(false)}
                                    className="block text-center text-sm font-medium text-accent-600 hover:text-accent-700 hover:underline"
                                >
                                    Ver todas notificações →
                                </Link>
                            </div>
                        )}
                    </div>
                </>
            )}
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import {
    BarChart,
    Bar,
    LineChart,
    Line,
    PieChart,
    Pie,
    Cell,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer
} from 'recharts'
import { createClient } from '@/lib/supabase/client'
import { TrendingUp, Users, Eye, Clock, MapPin, Smartphone } from 'lucide-react'

const supabase = createClient()

const COLORS = ['#C49D5B', '#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6']

interface TrackingAnalytics {
    totalClicks: number
    totalViews: number
    avgTimeOnPage: number
    conversionRate: number
    topSource: string
    topDevice: string
    topLocation: string
    clicksBySource: Array<{ name: string; value: number }>
    clicksByDevice: Array<{ name: string; value: number }>
    clicksByDay: Array<{ day: string; clicks: number }>
    topCampaigns: Array<{ campaign: string; clicks: number; conversions: number; roi: number }>
}

export default function TrackingAnalytics({ developmentId }: { developmentId?: string }) {
    const [analytics, setAnalytics] = useState<TrackingAnalytics | null>(null)
    const [loading, setLoading] = useState(true)
    const [timeRange, setTimeRange] = useState<'7d' | '30d' | '90d'>('30d')

    useEffect(() => {
        loadAnalytics()
    }, [developmentId, timeRange])

    const loadAnalytics = async () => {
        setLoading(true)

        try {
            const daysAgo = timeRange === '7d' ? 7 : timeRange === '30d' ? 30 : 90
            const startDate = new Date()
            startDate.setDate(startDate.getDate() - daysAgo)

            // Buscar eventos de tracking
            let query = supabase
                .from('link_events')
                .select('*, tracked_link:tracked_links(*)')
                .gte('created_at', startDate.toISOString())

            if (developmentId) {
                // We need to filter by tracked_link.development_id. 
                // Supabase join filtering syntax: !inner join to filter parent by child condition
                // But here we are filtering child (link_events) by parent (tracked_link) property?
                // Actually, link_events has tracked_link_id. We need to find tracked_links for this developmentId first if we want to be efficient,
                // OR use the relationship filter. 

                // Let's use the straightforward approach supported by storing tracked_link_id directly or join filtering.
                // Assuming we are querying link_events, we can filter by the joined table column if we use !inner
                query = query.eq('tracked_link.development_id', developmentId)
                // Note: For this to work in Supabase/PostgREST, we normally need !inner on the select if filtering by referenced table.
                // select('*, tracked_link!inner(*)')
            }

            // To be safe and generic for now, let's adjust the query slightly to ensure it works with standard PostgREST
            // Re-constructing the query
            let baseQuery = supabase
                .from('link_events')
                .select('*, tracked_link:tracked_links!inner(*)') // !inner is required to filter by joined table properties
                .gte('created_at', startDate.toISOString())

            if (developmentId) {
                baseQuery = baseQuery.eq('tracked_link.development_id', developmentId)
            }

            const { data: events, error } = await baseQuery

            if (error) {
                console.error('Error fetching analytics:', error)
                throw error
            }

            if (!events || events.length === 0) {
                setAnalytics({
                    totalClicks: 0,
                    totalViews: 0,
                    avgTimeOnPage: 0,
                    conversionRate: 0,
                    topSource: 'N/A',
                    topDevice: 'N/A',
                    topLocation: 'N/A',
                    clicksBySource: [],
                    clicksByDevice: [],
                    clicksByDay: [],
                    topCampaigns: []
                })
                setLoading(false)
                return
            }

            // Processar dados
            const totalClicks = events.length
            const totalViews = events.filter(e => e.event_type === 'page_view').length

            // Tempo médio (simulado - em produção viria de um campo real)
            const avgTimeOnPage = events
                .filter(e => e.metadata?.time_on_page)
                .reduce((sum, e) => sum + (e.metadata.time_on_page || 0), 0) / (totalViews || 1) || 0

            // Conversões (leads gerados a partir de links)
            const conversions = events.filter(e => e.metadata?.converted).length
            const conversionRate = totalClicks > 0 ? (conversions / totalClicks) * 100 : 0

            // Top source
            const sourceCounts: Record<string, number> = {}
            events.forEach(e => {
                const source = e.utm_params?.source || 'direct'
                sourceCounts[source] = (sourceCounts[source] || 0) + 1
            })
            const topSource = Object.entries(sourceCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A'

            // Top device
            const deviceCounts: Record<string, number> = {}
            events.forEach(e => {
                const device = e.device_type || 'desktop'
                deviceCounts[device] = (deviceCounts[device] || 0) + 1
            })
            const topDevice = Object.entries(deviceCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A'

            // Top location
            const locationCounts: Record<string, number> = {}
            events.forEach(e => {
                const location = e.location || 'Unknown'
                locationCounts[location] = (locationCounts[location] || 0) + 1
            })
            const topLocation = Object.entries(locationCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'N/A'

            // Clicks by source
            const clicksBySource = Object.entries(sourceCounts)
                .map(([name, value]) => ({ name, value }))
                .sort((a, b) => b.value - a.value)
                .slice(0, 5)

            // Clicks by device
            const clicksByDevice = Object.entries(deviceCounts)
                .map(([name, value]) => ({
                    name: name === 'mobile' ? 'Mobile' : name === 'desktop' ? 'Desktop' : 'Tablet',
                    value
                }))

            // Clicks by day (últimos 7 dias)
            const lastDaysCount = timeRange === '7d' ? 7 : timeRange === '30d' ? 30 : 90
            // For chart readability, if 90 days, maybe group by week? Keeping simple for now.

            const clicksByDayMap: Record<string, number> = {}
            events.forEach(e => {
                const day = e.created_at.split('T')[0]
                clicksByDayMap[day] = (clicksByDayMap[day] || 0) + 1
            })

            // Generate dates for the range
            const clicksByDay = []
            for (let i = lastDaysCount - 1; i >= 0; i--) {
                const date = new Date()
                date.setDate(date.getDate() - i)
                const dayKey = date.toISOString().split('T')[0]
                clicksByDay.push({
                    day: date.toLocaleDateString('pt-BR', { day: '2-digit', month: 'short' }),
                    clicks: clicksByDayMap[dayKey] || 0
                })
            }

            // Top campaigns
            const campaignStats: Record<string, { clicks: number; conversions: number }> = {}
            events.forEach(e => {
                const campaign = e.utm_params?.campaign || 'sem_campanha'
                if (!campaignStats[campaign]) {
                    campaignStats[campaign] = { clicks: 0, conversions: 0 }
                }
                campaignStats[campaign].clicks++
                if (e.metadata?.converted) {
                    campaignStats[campaign].conversions++
                }
            })

            const topCampaigns = Object.entries(campaignStats)
                .map(([campaign, stats]) => ({
                    campaign,
                    clicks: stats.clicks,
                    conversions: stats.conversions,
                    roi: stats.clicks > 0 ? (stats.conversions / stats.clicks) * 100 : 0
                }))
                .sort((a, b) => b.clicks - a.clicks)
                .slice(0, 5)

            setAnalytics({
                totalClicks,
                totalViews,
                avgTimeOnPage: Math.round(avgTimeOnPage),
                conversionRate: parseFloat(conversionRate.toFixed(2)),
                topSource,
                topDevice,
                topLocation,
                clicksBySource,
                clicksByDevice,
                clicksByDay,
                topCampaigns
            })

        } catch (error) {
            console.error('Erro ao carregar analytics:', error)
        } finally {
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center h-96">
                <div className="text-center">
                    <div className="w-16 h-16 border-4 border-accent-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
                    <p className="text-imi-600">Carregando analytics...</p>
                </div>
            </div>
        )
    }

    if (!analytics) return null

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Time Range Selector */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <h2 className="text-2xl font-bold text-imi-900">Analytics de Tracking</h2>
                <div className="flex gap-2">
                    {[
                        { value: '7d', label: '7 dias' },
                        { value: '30d', label: '30 dias' },
                        { value: '90d', label: '90 dias' }
                    ].map((option) => (
                        <button
                            key={option.value}
                            onClick={() => setTimeRange(option.value as any)}
                            className={`px-4 py-2 rounded-xl font-medium transition-all text-sm ${timeRange === option.value
                                    ? 'bg-accent-500 text-white shadow-md'
                                    : 'bg-white border border-imi-200 text-imi-700 hover:border-accent-300 hover:bg-imi-50'
                                }`}
                        >
                            {option.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* KPIs */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="bg-blue-50/50 rounded-2xl border border-blue-200 p-6 hover:shadow-md transition-shadow">
                    <div className="flex items-center gap-3 mb-2">
                        <Eye size={24} className="text-blue-600" />
                        <span className="text-sm font-medium text-blue-700">Total Eventos</span>
                    </div>
                    <div className="text-3xl font-bold text-blue-900">{analytics.totalClicks}</div>
                </div>

                <div className="bg-green-50/50 rounded-2xl border border-green-200 p-6 hover:shadow-md transition-shadow">
                    <div className="flex items-center gap-3 mb-2">
                        <Users size={24} className="text-green-600" />
