'use client'

import { useEffect, useState } from 'react'
import {
    Users,
    Building2,
    TrendingUp,
    FileText,
    Calendar,
    MessageSquare,
    DollarSign,
    Star,
    ArrowRight,
    Clock
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { useRealtimeDevelopments, useRealtimeLeads } from '@/hooks/use-realtime-sync'
import { formatDistanceToNow } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import Link from 'next/link'

const supabase = createClient()

interface Activity {
    id: string
    type: 'lead' | 'development' | 'status_change' | 'evaluation' | 'consultation' | 'meeting' | 'high_score'
    title: string
    description: string
    timestamp: string
    link?: string
    icon: any
    color: string
    bgColor: string
    priority: 'high' | 'medium' | 'low'
}

export default function DashboardRecentActivity() {
    const [activities, setActivities] = useState<Activity[]>([])
    const [loading, setLoading] = useState(true)

    // Real-time updates
    useRealtimeDevelopments((dev) => {
        addActivity({
            type: 'development',
            title: 'Novo Empreendimento',
            description: `${dev.name} foi adicionado`,
            timestamp: new Date().toISOString(),
            link: `/backoffice/imoveis/${dev.id}`,
            priority: 'medium'
        })
    })

    useRealtimeLeads((lead) => {
        const isHighScore = (lead.score || 0) >= 80

        addActivity({
            type: isHighScore ? 'high_score' : 'lead',
            title: isHighScore ? 'Lead Qualificado!' : 'Novo Lead',
            description: `${lead.name} ${isHighScore ? `(Score: ${lead.score})` : ''}`,
            timestamp: new Date().toISOString(),
            link: `/backoffice/leads/${lead.id}`,
            priority: isHighScore ? 'high' : 'low'
        })
    })

    useEffect(() => {
        loadActivities()
    }, [])

    const loadActivities = async () => {
        setLoading(true)
        try {
            const allActivities: Activity[] = []

            // 1. Buscar leads recentes (últimas 24h)
            const oneDayAgo = new Date()
            oneDayAgo.setDate(oneDayAgo.getDate() - 1)

            const { data: recentLeads } = await supabase
                .from('leads')
                .select('id, name, score, created_at, status')
                .gte('created_at', oneDayAgo.toISOString())
                .order('created_at', { ascending: false })
                .limit(10)

            recentLeads?.forEach(lead => {
                const isHighScore = (lead.score || 0) >= 80
                allActivities.push({
                    id: `lead-${lead.id}`,
                    type: isHighScore ? 'high_score' : 'lead',
                    title: isHighScore ? 'Lead Qualificado!' : 'Novo Lead',
                    description: `${lead.name}${isHighScore ? ` (Score: ${lead.score})` : ''}`,
                    timestamp: lead.created_at,
                    link: `/backoffice/leads/${lead.id}`,
                    icon: isHighScore ? Star : Users,
                    color: isHighScore ? 'text-yellow-600' : 'text-blue-600',
                    bgColor: isHighScore ? 'bg-yellow-50' : 'bg-blue-50',
                    priority: isHighScore ? 'high' : 'low'
                })
            })

            // 2. Buscar mudanças de status (últimas 24h)
            const { data: statusChanges } = await supabase
                .from('leads')
                .select('id, name, status, updated_at')
                .gte('updated_at', oneDayAgo.toISOString())
                .neq('created_at', 'updated_at') // Apenas atualizações, não criações
                .order('updated_at', { ascending: false })
                .limit(8)

            statusChanges?.forEach(lead => {
                const isWon = lead.status === 'won'
                allActivities.push({
                    id: `status-${lead.id}`,
                    type: 'status_change',
                    title: isWon ? 'Negócio Fechado! 🎉' : 'Status Atualizado',
                    description: `${lead.name} → ${getStatusName(lead.status)}`,
                    timestamp: lead.updated_at,
                    link: `/backoffice/leads/${lead.id}`,
                    icon: isWon ? TrendingUp : ArrowRight,
                    color: isWon ? 'text-green-600' : 'text-purple-600',
                    bgColor: isWon ? 'bg-green-50' : 'bg-purple-50',
                    priority: isWon ? 'high' : 'medium'
                })
            })

            // 3. Buscar empreendimentos recentes
            const { data: recentDevs } = await supabase
                .from('developments')
                .select('id, name, created_at, status')
                .gte('created_at', oneDayAgo.toISOString())
                .order('created_at', { ascending: false })
                .limit(5)

            recentDevs?.forEach(dev => {
                const isPublished = dev.status === 'published'
                allActivities.push({
                    id: `dev-${dev.id}`,
                    type: 'development',
                    title: isPublished ? 'Empreendimento Publicado' : 'Novo Empreendimento',
                    description: dev.name,
                    timestamp: dev.created_at,
                    link: `/backoffice/imoveis/${dev.id}`,
                    icon: Building2,
                    color: 'text-orange-600',
                    bgColor: 'bg-orange-50',
                    priority: isPublished ? 'medium' : 'low'
                })
            })

            // 4. Buscar avaliações recentes
            const { data: evaluations } = await supabase
                .from('property_evaluations')
                .select('id, property_address, created_at')
                .gte('created_at', oneDayAgo.toISOString())
                .order('created_at', { ascending: false })
                .limit(5)

            evaluations?.forEach(val => {
                allActivities.push({
                    id: `eval-${val.id}`,
                    type: 'evaluation',
                    title: 'Nova Avaliação Solicitada',
                    description: val.property_address,
                    timestamp: val.created_at,
                    link: `/backoffice/avaliacoes/${val.id}`,
                    icon: FileText,
                    color: 'text-pink-600',
                    bgColor: 'bg-pink-50',
                    priority: 'medium'
                })
            })

            // 5. Buscar consultorias recentes
            const { data: consultations } = await supabase
                .from('consultations')
                .select('id, name, created_at')
                .gte('created_at', oneDayAgo.toISOString())
                .order('created_at', { ascending: false })
                .limit(5)

            consultations?.forEach(cons => {
                allActivities.push({
                    id: `cons-${cons.id}`,
                    type: 'consultation',
                    title: 'Nova Solicitação de Consultoria',
                    description: cons.name,
                    timestamp: cons.created_at,
                    link: `/backoffice/consultations/${cons.id}`,
                    icon: MessageSquare,
                    color: 'text-indigo-600',
                    bgColor: 'bg-indigo-50',
                    priority: 'high'
                })
            })

            // Ordenar por timestamp e prioridade
            allActivities.sort((a, b) => {
                // Primeiro por prioridade
                const priorityOrder = { high: 0, medium: 1, low: 2 }
                if (priorityOrder[a.priority] !== priorityOrder[b.priority]) {
                    return priorityOrder[a.priority] - priorityOrder[b.priority]
                }
                // Depois por timestamp
                return new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
            })

            setActivities(allActivities.slice(0, 15)) // Mostrar apenas os 15 mais relevantes

        } catch (error) {
            console.error('Erro ao carregar atividades:', error)
        } finally {
            setLoading(false)
        }
    }

    const addActivity = (activity: Omit<Activity, 'id' | 'icon' | 'color' | 'bgColor'>) => {
        const config = getActivityConfig(activity.type)
        const newActivity: Activity = {
            ...activity,
            id: `${activity.type}-${Date.now()}`,
            icon: config.icon,
            color: config.color,
            bgColor: config.bgColor
        }

        setActivities(prev => [newActivity, ...prev].slice(0, 15))
    }

    const getActivityConfig = (type: Activity['type']) => {
        const configs = {
            lead: { icon: Users, color: 'text-blue-600', bgColor: 'bg-blue-50' },
            development: { icon: Building2, color: 'text-orange-600', bgColor: 'bg-orange-50' },
            status_change: { icon: ArrowRight, color: 'text-purple-600', bgColor: 'bg-purple-50' },
            evaluation: { icon: FileText, color: 'text-pink-600', bgColor: 'bg-pink-50' },
            consultation: { icon: MessageSquare, color: 'text-indigo-600', bgColor: 'bg-indigo-50' },
            meeting: { icon: Calendar, color: 'text-teal-600', bgColor: 'bg-teal-50' },
            high_score: { icon: Star, color: 'text-yellow-600', bgColor: 'bg-yellow-50' }
        }
        return (configs as any)[type] || configs.lead
    }

    const getStatusName = (status: string): string => {
        const names: Record<string, string> = {
            new: 'Novo',
            contacted: 'Contatado',
            qualified: 'Qualificado',
            proposal: 'Proposta',
            negotiation: 'Negociação',
            won: 'Ganho',
            lost: 'Perdido'
        }
        return names[status] || status
    }

    if (loading) {
        return (
            <div className="bg-white rounded-2xl border border-imi-100 p-6">
                <h3 className="text-lg font-bold text-imi-900 mb-6">Atividade Recente</h3>
                <div className="space-y-4">
                    {[...Array(5)].map((_, i) => (
                        <div key={i} className="flex items-start gap-4 animate-pulse">
                            <div className="w-12 h-12 rounded-xl bg-imi-100" />
                            <div className="flex-1 space-y-2">
                                <div className="h-4 bg-imi-100 rounded w-3/4" />
                                <div className="h-3 bg-imi-100 rounded w-1/2" />
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        )
    }

    return (
        <div className="bg-white rounded-2xl border border-imi-100 p-6">
            <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-imi-900 flex items-center gap-2">
                    <Clock size={24} className="text-accent-600" />
                    Atividade Recente
                </h3>
                <div className="text-xs text-imi-500">Últimas 24h</div>
            </div>

            {activities.length === 0 ? (
                <div className="text-center py-12">
                    <Clock size={48} className="text-imi-300 mx-auto mb-4" />
                    <p className="text-imi-600">Nenhuma atividade recente</p>
                </div>
            ) : (
                <div className="space-y-3">
                    {activities.map((activity, index) => {
                        const Icon = activity.icon
                        const isRecent = new Date().getTime() - new Date(activity.timestamp).getTime() < 3600000 // < 1 hora

                        return (
                            <Link
                                key={activity.id}
                                href={activity.link || '#'}
                                className="block group"
                            >
                                <div className={`flex items-start gap-4 p-4 rounded-xl transition-all ${activity.priority === 'high'
                                        ? 'bg-gradient-to-r from-accent-50 to-white border border-accent-200'
                                        : 'hover:bg-imi-50'
                                    }`}>
                                    {/* Icon */}
                                    <div className={`w-12 h-12 rounded-xl ${activity.bgColor} flex items-center justify-center flex-shrink-0 group-hover:scale-110 transition-transform`}>
                                        <Icon size={20} className={activity.color} />
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-start justify-between gap-2">
                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center gap-2">
                                                    <h4 className="font-semibold text-imi-900 truncate">
                                                        {activity.title}
                                                    </h4>
                                                    {isRecent && (
                                                        <span className="flex-shrink-0 px-2 py-0.5 text-xs font-medium bg-red-100 text-red-700 rounded">
                                                            Novo
                                                        </span>
                                                    )}
                                                    {activity.priority === 'high' && (
                                                        <span className="flex-shrink-0 px-2 py-0.5 text-xs font-medium bg-accent-100 text-accent-700 rounded">
                                                            Alta
                                                        </span>
                                                    )}
                                                </div>
                                                <p className="text-sm text-imi-600 truncate mt-1">
                                                    {activity.description}
                                                </p>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-2 mt-2">
                                            <span className="text-xs text-imi-500">
                                                {formatDistanceToNow(new Date(activity.timestamp), {
                                                    addSuffix: true,
                                                    locale: ptBR
                                                })}
                                            </span>
                                            <span className="text-imi-300">•</span>
                                            <span className="text-xs text-accent-600 opacity-0 group-hover:opacity-100 transition-opacity">
                                                Ver detalhes →
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            </Link>
                        )
                    })}
                </div>
            )}

            {/* Footer Stats */}
            <div className="mt-6 pt-6 border-t border-imi-100 grid grid-cols-3 gap-4 text-center">
                <div>
                    <div className="text-2xl font-bold text-blue-600">
                        {activities.filter(a => a.type === 'lead' || a.type === 'high_score').length}
                    </div>
                    <div className="text-xs text-imi-500 mt-1">Novos Leads</div>
                </div>
                <div>
                    <div className="text-2xl font-bold text-green-600">
                        {activities.filter(a => a.type === 'status_change' && a.title.includes('Fechado')).length}
                    </div>
                    <div className="text-xs text-imi-500 mt-1">Fechamentos</div>
                </div>
                <div>
                    <div className="text-2xl font-bold text-purple-600">
                        {activities.filter(a => a.type === 'status_change').length}
                    </div>
                    <div className="text-xs text-imi-500 mt-1">Movimentos</div>
                </div>
            </div>
        </div>
    )
}

'use client'

import React, { useState } from 'react'
import {
    Image as ImageIcon,
    Video,
    FileImage,
    X,
    Trash2,
    Eye,
    MoveUp,
    Building2
} from 'lucide-react'
import { uploadImage, uploadFile, deleteFile } from '@/lib/supabase-storage'
import { toast } from 'sonner'
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent
} from '@dnd-kit/core'
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    rectSortingStrategy,
    useSortable
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'

// Interfaces
interface MediaUploaderProps {
    type: 'gallery' | 'videos' | 'floorplans' | 'logo'
    label: string
    description?: string
    value: string[]
    onChange: (urls: string[]) => void
    maxFiles?: number
    entityId?: string // Renamed from developmentId to be generic
    entityType?: 'development' | 'developer' // New prop
}

interface SortableImageProps {
    id: string
    url: string
    onDelete: (id: string) => void
    onView: (url: string) => void
}

// Subcomponente SortableImage
function SortableImage({ id, url, onDelete, onView }: SortableImageProps) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging
    } = useSortable({ id })

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
        opacity: isDragging ? 0.5 : 1,
        zIndex: isDragging ? 10 : 1
    }

    return (
        <div
            ref={setNodeRef}
            style={style}
            className={`group relative aspect-video bg-gray-50 dark:bg-card-dark rounded-xl overflow-hidden border-2 transition-all ${isDragging ? 'border-primary shadow-lg scale-105' : 'border-gray-100 dark:border-white/5 hover:border-primary/50'}`}
            {...attributes}
            {...listeners}
        >
            <img
                src={url}
                alt="Media"
                className="w-full h-full object-cover"
            />

            {/* Overlay com ações */}
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-3">
                <div className="flex items-center justify-end gap-2">
                    <button
                        type="button"
                        onClick={(e) => {
                            e.preventDefault()
                            e.stopPropagation()
                            onView(url)
                        }}
                        className="p-2 rounded-lg bg-white/20 backdrop-blur-sm text-white hover:bg-white/30 transition-colors"
                        title="Visualizar"
                    >
                        <Eye size={16} />
                    </button>
                    <button
                        type="button"
                        onClick={(e) => {
                            e.preventDefault()
                            e.stopPropagation()
                            onDelete(id)
                        }}
                        className="p-2 rounded-lg bg-red-500/80 backdrop-blur-sm text-white hover:bg-red-600 transition-colors"
                        title="Excluir"
                    >
                        <Trash2 size={16} />
                    </button>
                </div>
            </div>

            {/* Badge de índice */}
            <div className="absolute top-2 left-2 pointer-events-none">
                <div className="w-6 h-6 rounded bg-black/50 backdrop-blur-sm flex items-center justify-center text-xs font-bold text-white border border-white/10">
                    {parseInt(id) + 1}
                </div>
            </div>
        </div>
    )
}

// Componente Principal
export default function MediaUploader({
    type,
    label,
    description,
    value = [],
    onChange,
    maxFiles = 20,
    entityId,
    entityType = 'development',
    // Backward compatibility props (if any code still uses developmentId)
    ...props
}: MediaUploaderProps & { developmentId?: string }) {
    const [uploading, setUploading] = useState(false)
    const [progress, setProgress] = useState(0)
    const [previewUrl, setPreviewUrl] = useState<string | null>(null)

    // Handle backward compatibility
    const actualEntityId = entityId || props.developmentId

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates
        })
    )

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event

        if (over && active.id !== over.id) {
            const oldIndex = parseInt(active.id as string)
            const newIndex = parseInt(over.id as string)
            const reordered = arrayMove(value, oldIndex, newIndex)
            onChange(reordered)
            toast.success('Ordem atualizada!')
        }
    }

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || [])

        if (files.length === 0) return

        if (value.length + files.length > maxFiles) {
            toast.error(`Máximo de ${maxFiles} arquivos permitidos`)
            return
        }

        setUploading(true)
        const uploadedUrls: string[] = []

        // Calcula progresso total baseado no número de arquivos
        const totalFiles = files.length

        for (let i = 0; i < totalFiles; i++) {
            const file = files[i]

            // Atualiza progresso geral (simplificado)
            setProgress(Math.round(((i) / totalFiles) * 100))

            try {
                let result

                // Define a pasta base (pluraliza o entityType para o nome do bucket/pasta)
                const folderName = entityType === 'developer' ? 'developers' : 'developments'
                const folderPath = `${folderName}/${actualEntityId || 'temp'}/${type}`

                if (type === 'videos') {
                    // Upload de vídeo
                    result = await uploadFile(
                        file,
                        'media',
                        folderPath
                    )
                } else {
                    // Upload de imagem (com otimização)
                    result = await uploadImage(file, {
                        folder: folderPath,
                        maxWidth: type === 'floorplans' ? 2000 : 1920,
                        maxHeight: type === 'floorplans' ? 2000 : 1080,
                        quality: 0.85
                    })
                }

                if (result.error) {
                    toast.error(`Erro no arquivo ${file.name}: ${result.error}`)
                } else {
                    uploadedUrls.push(result.url)
                }
            } catch (error) {
                console.error('Erro no upload:', error)
                toast.error(`Erro ao enviar ${file.name}`)
            }
        }

        if (uploadedUrls.length > 0) {
            // Adiciona novos URLs à lista existente
            onChange([...value, ...uploadedUrls])
            toast.success(`${uploadedUrls.length} arquivo(s) enviado(s)!`)
        }

        setUploading(false)
        setProgress(0)

        // Limpar input para permitir selecionar o mesmo arquivo novamente se necessário
        e.target.value = ''
    }

    const handleDelete = async (id: string) => {
        const index = parseInt(id)
        if (confirm('Tem certeza que deseja remover este arquivo?')) {
            const urlToDelete = value[index]

            // Tentar extrair path do URL para deletar do storage
            try {
                const urlObj = new URL(urlToDelete)
                const pathParts = urlObj.pathname.split('/media/')
                if (pathParts.length > 1) {
                    const path = pathParts[1]
                    await deleteFile(path, 'media')
                }
            } catch (err) {
                console.warn('Não foi possível extrair o caminho do arquivo para deleção física (ignorando)', err)
            }

            const newUrls = value.filter((_, i) => i !== index)
            onChange(newUrls)
            toast.success('Arquivo removido!')
        }
    }

    const handleView = (url: string) => {
        setPreviewUrl(url)
    }

    // Determina ícone e tipos aceitos
    let Icon = ImageIcon
    let accept = 'image/*'
    let hint = 'JPG, PNG ou WEBP (máx 10MB)'

    if (type === 'videos') {
        Icon = Video
        accept = 'video/mp4,video/quicktime'
        hint = 'MP4 ou MOV (máx 50MB)'
    } else if (type === 'floorplans') {
        Icon = FileImage
        accept = 'image/*'
        hint = 'Plantas em alta resolução'
    } else if (type === 'logo') {
        Icon = Building2
        accept = 'image/*'
        hint = 'Logo em PNG ou SVG preferencialmente'
    }

    // IDs para DnD (índices como string)
    const items = value.map((_, i) => i.toString())

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <label className="block text-sm font-bold text-gray-700 dark:text-gray-300">
                        {label}
                    </label>
                    {description && (
                        <p className="text-xs text-gray-500 mt-1">{description}</p>
                    )}
                </div>
                <div className="text-xs font-medium px-2 py-1 rounded bg-gray-100 dark:bg-white/5 text-gray-500 border border-gray-200 dark:border-white/10">
                    {value.length} / {maxFiles}
                </div>
            </div>

            {/* Upload Area */}
            {value.length < maxFiles && (
                <label className="block group">
                    <input
                        type="file"
                        multiple
                        accept={accept}
                        onChange={handleFileSelect}
                        disabled={uploading}
                        className="hidden"
                    />
                    <div className={`relative border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all overflow-hidden ${uploading
                        ? 'border-primary/50 bg-primary/5 cursor-wait'
                        : 'border-gray-200 dark:border-white/10 hover:border-primary/50 hover:bg-gray-50 dark:hover:bg-white/5'
                        }`}>
                        {uploading ? (
                            <div className="flex flex-col items-center justify-center py-2">
                                {/* Spinner circular com progresso */}
                                <div className="relative w-16 h-16 mb-4">
                                    <svg className="w-full h-full transform -rotate-90">
                                        <circle
                                            cx="32"
                                            cy="32"
                                            r="28"
                                            stroke="currentColor"
                                            strokeWidth="4"
                                            fill="none"
                                            className="text-gray-200 dark:text-gray-700"
                                        />
                                        <circle
                                            cx="32"
                                            cy="32"
                                            r="28"
                                            stroke="currentColor"
                                            strokeWidth="4"
                                            fill="none"
                                            strokeDasharray={`${2 * Math.PI * 28}`}
                                            strokeDashoffset={`${2 * Math.PI * 28 * (1 - progress / 100)}`}
                                            className="text-primary transition-all duration-300"
                                            strokeLinecap="round"
                                        />
                                    </svg>
                                    <div className="absolute inset-0 flex items-center justify-center text-xs font-bold text-primary">
                                        {progress}%
                                    </div>
                                </div>
                                <p className="text-sm font-medium text-primary animate-pulse">Otimizando e enviando...</p>
                            </div>
                        ) : (
                            <>
                                <div className="w-16 h-16 rounded-full bg-gray-50 dark:bg-white/5 flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform duration-300">
                                    <Icon size={32} className="text-gray-400 dark:text-gray-500 group-hover:text-primary transition-colors" />
                                </div>
                                <p className="text-sm font-medium text-gray-900 dark:text-white mb-1">
                                    Clique ou arraste arquivos
                                </p>
                                <p className="text-xs text-gray-500">
                                    {hint}
                                </p>
                            </>
                        )}
                    </div>
                </label>
            )}

            {/* Gallery Grid (Sortable) */}
            {value.length > 0 && (
                <DndContext
                    sensors={sensors}
                    collisionDetection={closestCenter}
                    onDragEnd={handleDragEnd}
                >
                    <SortableContext
                        items={items}
                        strategy={rectSortingStrategy}
                    >
                        <div className={`grid gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500 ${type === 'logo' ? 'grid-cols-1 w-full max-w-[300px]' : 'grid-cols-2 lg:grid-cols-4'
                            }`}>
                            {value.map((url, index) => (
                                <SortableImage
                                    key={index} // Usando index como chave estável para o map, mas o ID do sortable é string do index
                                    id={index.toString()}
                                    url={url}
                                    onDelete={handleDelete}
                                    onView={handleView}
                                />
                            ))}
                        </div>
                    </SortableContext>
                </DndContext>
            )}

            {/* Hint de reordenação */}
            {value.length > 1 && (
                <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400 px-1">
                    <MoveUp size={12} />
                    <span>Arraste para reordenar</span>
                </div>
            )}

            {/* Preview Modal */}
            {previewUrl && (
                <div
                    className="fixed inset-0 bg-black/90 backdrop-blur-md z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200"
                    onClick={() => setPreviewUrl(null)}
                >
                    <div className="relative max-w-7xl w-full max-h-[90vh] flex flex-col items-center">
                        <button
                            onClick={() => setPreviewUrl(null)}
                            className="absolute -top-12 right-0 p-2 rounded-full bg-white/10 text-white hover:bg-white/20 transition-colors"
                        >
                            <X size={24} />
                        </button>

                        {type === 'videos' ? (
                            <video
                                src={previewUrl}
                                controls
                                autoPlay
                                className="max-w-full max-h-[85vh] rounded-lg shadow-2xl"
                                onClick={(e) => e.stopPropagation()}
                            />
                        ) : (
                            <img
                                src={previewUrl}
                                alt="Preview"
                                className="max-w-full max-h-[85vh] object-contain rounded-lg shadow-2xl"
                                onClick={(e) => e.stopPropagation()}
                            />
                        )}
                    </div>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { ExternalLink, Copy, Check, MousePointer2, Calendar, Plus, Link as LinkIcon, Loader2 } from 'lucide-react'
import Button from '@/components/ui/Button'
import TrackingLinkModal from './TrackingLinkModal'
import { Development } from '@/types/development'
import { useToast } from '@/components/ui/Toast'

interface TrackedLinksListProps {
    propertyId: string
    property: Development
}

interface TrackedLink {
    id: string
    short_code: string
    original_url: string
    clicks: number
    created_at: string
}

export default function TrackedLinksList({ propertyId, property }: TrackedLinksListProps) {
    const supabase = createClient()
    const { showToast } = useToast()
    const [links, setLinks] = useState<TrackedLink[]>([])
    const [isLoading, setIsLoading] = useState(true)
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [copiedId, setCopiedId] = useState<string | null>(null)

    async function fetchLinks() {
        // setIsLoading(true) // Don't reset full loading on refresh, maybe just use SWR next time
        const { data, error } = await supabase
            .from('tracked_links')
            .select('*')
            .eq('property_id', propertyId)
            .order('created_at', { ascending: false })

        if (!error && data) {
            setLinks(data)
        }
        setIsLoading(false)
    }

    useEffect(() => {
        fetchLinks()
    }, [propertyId])

    const handleCopy = async (link: TrackedLink) => {
        const url = `${window.location.origin}/l/${link.short_code}`
        await navigator.clipboard.writeText(url)
        setCopiedId(link.id)
        showToast('Link copiado', 'success')
        setTimeout(() => setCopiedId(null), 2000)
    }

    if (isLoading) {
        return (
            <div className="flex flex-col items-center justify-center py-20 bg-imi-50 rounded-3xl border border-dashed border-imi-100 animate-pulse">
                <Loader2 className="w-8 h-8 text-imi-400 animate-spin mb-4" />
                <p className="text-imi-400 font-bold text-xs uppercase tracking-widest">Sincronizando Links...</p>
            </div>
        )
    }

    return (
        <section className="space-y-8 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="max-w-xl">
                    <h2 className="font-display text-2xl text-imi-900 mb-2 font-bold tracking-tight">Campanhas & Rastreamento</h2>
                    <p className="text-imi-500 text-sm font-medium">
                        Gerencie links exclusivos para identificar a origem dos leads e otimizar suas campanhas.
                    </p>
                </div>
                <Button onClick={() => setIsModalOpen(true)} className="h-12 px-6 bg-imi-900 text-white rounded-xl shadow-elevated group active:scale-95 transition-all font-bold uppercase tracking-widest text-xs hover:bg-black">
                    <Plus className="w-4 h-4 mr-2 group-hover:rotate-90 transition-transform" />
                    Novo Rastreador
                </Button>
            </div>

            {links.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-imi-100">
                    <LinkIcon className="w-12 h-12 mx-auto mb-4 text-imi-100" />
                    <h3 className="text-imi-900 font-bold mb-1">Nenhum link ativo</h3>
                    <p className="text-xs text-imi-400 font-medium">Gere links parametrizados para rastrear seus anúncios.</p>
                </div>
            ) : (
                <div className="grid gap-4">
                    {links.map((link) => (
                        <div key={link.id} className="bg-white rounded-2xl p-6 border border-imi-100 shadow-soft hover:shadow-md transition-all flex flex-col md:flex-row justify-between items-start md:items-center gap-6 group">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-imi-50 rounded-xl flex items-center justify-center text-imi-400 group-hover:bg-imi-900 group-hover:text-white transition-colors">
                                    <LinkIcon size={20} />
                                </div>
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <h3 className="font-bold text-imi-900 uppercase tracking-tight text-sm font-mono bg-imi-50 px-2 py-1 rounded-lg border border-imi-100">
                                            /l/{link.short_code}
                                        </h3>
                                    </div>
                                    <p className="text-[10px] text-imi-400 truncate max-w-md font-medium uppercase tracking-wider">
                                        {link.original_url.split('?')[1]?.replace(/&/g, ' • ') || 'Link Direto'}
                                    </p>
                                </div>
                            </div>

                            <div className="flex items-center gap-8 w-full md:w-auto">
                                <div className="text-center md:border-r border-imi-50 pr-8">
                                    <div className="flex items-center justify-center gap-2 text-imi-900 font-black text-xl">
                                        <MousePointer2 size={16} className="text-imi-300" />
                                        {link.clicks || 0}
                                    </div>
                                    <div className="text-[9px] font-black text-imi-300 uppercase tracking-widest">Cliques</div>
                                </div>

                                <div className="text-center hidden sm:block">
                                    <div className="flex items-center justify-center gap-2 text-imi-500 font-bold text-sm">
                                        <Calendar size={14} className="text-imi-200" />
                                        {new Date(link.created_at).toLocaleDateString('pt-BR')}
                                    </div>
                                    <div className="text-[9px] font-black text-imi-300 uppercase tracking-widest">Criado em</div>
                                </div>

                                <div className="flex gap-2 ml-auto">
                                    <button
                                        onClick={() => handleCopy(link)}
                                        className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all active:scale-95 ${copiedId === link.id
                                            ? 'bg-green-500 border-green-500 text-white'
                                            : 'border-imi-100 text-imi-400 hover:text-imi-900 hover:bg-imi-50 bg-white'
                                            }`}
                                    >
                                        {copiedId === link.id ? <Check size={18} /> : <Copy size={18} />}
                                    </button>
                                    <a
                                        href={link.original_url}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="w-10 h-10 rounded-xl border border-imi-100 flex items-center justify-center text-imi-400 hover:text-imi-900 hover:bg-imi-50 bg-white transition-all active:scale-95"
                                    >
                                        <ExternalLink size={18} />
                                    </a>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {isModalOpen && (
                <TrackingLinkModal
                    property={property}
                    onClose={() => {
                        setIsModalOpen(false)
                        fetchLinks()
                    }}
                />
            )}
        </section>
    )
}

'use client'

import React, { useState, useEffect } from 'react'
import {
    Plus,
    Phone,
    Mail,
    MessageSquare,
    Calendar,
    FileText,
    CheckCircle,
    Clock,
    User,
    Save,
    X,
    History
} from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'
import { formatDistanceToNow, format } from 'date-fns'
import { ptBR } from 'date-fns/locale'

const supabase = createClient()

interface Interaction {
    id: string
    lead_id: string
    type: 'call' | 'email' | 'whatsapp' | 'visit' | 'meeting' | 'note'
    title: string
    description: string
    outcome: string | null
    next_action: string | null
    next_action_date: string | null
    created_by: string
    created_at: string
    user?: {
        name: string
    }
}

const INTERACTION_TYPES = [
    { value: 'call', label: 'Ligação', icon: Phone, color: 'text-blue-600', bg: 'bg-blue-50', borderColor: 'border-blue-200' },
    { value: 'email', label: 'E-mail', icon: Mail, color: 'text-purple-600', bg: 'bg-purple-50', borderColor: 'border-purple-200' },
    { value: 'whatsapp', label: 'WhatsApp', icon: MessageSquare, color: 'text-green-600', bg: 'bg-green-50', borderColor: 'border-green-200' },
    { value: 'visit', label: 'Visita', icon: Calendar, color: 'text-orange-600', bg: 'bg-orange-50', borderColor: 'border-orange-200' },
    { value: 'meeting', label: 'Reunião', icon: User, color: 'text-pink-600', bg: 'bg-pink-50', borderColor: 'border-pink-200' },
    { value: 'note', label: 'Anotação', icon: FileText, color: 'text-gray-600', bg: 'bg-gray-50', borderColor: 'border-gray-200' }
]

interface InteractionsTimelineProps {
    leadId: string
}

export default function InteractionsTimeline({ leadId }: InteractionsTimelineProps) {
    const [interactions, setInteractions] = useState<Interaction[]>([])
    const [loading, setLoading] = useState(true)
    const [showForm, setShowForm] = useState(false)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [formData, setFormData] = useState({
        type: 'call' as const,
        title: '',
        description: '',
        outcome: '',
        next_action: '',
        next_action_date: ''
    })

    useEffect(() => {
        loadInteractions()
    }, [leadId])

    const loadInteractions = async () => {
        setLoading(true)
        const { data, error } = await supabase
            .from('lead_interactions')
            .select(`
        *,
        user:created_by (
            raw_user_meta_data
        )
      `) // Ajuste para buscar nome do usuário se profile não estiver configurado, ou view
        // Fallback para auth.users se view não acessível diretamente, mas idealmente seria profiles
        // Como a query original usava auth.users(name) que não é padrão no supabase-js client diretamente (precisa de view)
        // Vou simplificar assumindo que o hook traz os dados ou ajustaremos conforme a estrutura real.
        // Tentativa segura:

        //   .select(`*, user:profiles(name)`) // Se profiles existir

        // Por enquanto, usando uma query simples e tratando o user no frontend se necessário
        // Mas para manter a compatibilidade com o request original que pedia `user:auth.users(name)`:
        // O Supabase não permite join direto com auth.users via client a menos que existam FKs e views públicas.
        // Vou usar uma query padrão e tentar buscar o nome se possível, ou usar um placeholder.

        const { data: interactionsData, error: interactionsError } = await supabase
            .from('lead_interactions')
            .select('*')
            .eq('lead_id', leadId)
            .order('created_at', { ascending: false })

        if (interactionsError) {
            console.error('Error loading interactions:', interactionsError)
        } else {
            // Tentar enriquecer com dados de usuário se possível
            // Por simplicidade e segurança, vamos focar nos dados da interação
            setInteractions(interactionsData || [])
        }
        setLoading(false)
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!formData.title.trim() || !formData.description.trim()) {
            toast.error('Preencha título e descrição')
            return
        }

        setIsSubmitting(true)

        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            toast.error('Usuário não autenticado')
            setIsSubmitting(false)
            return
        }

        const { error } = await supabase
            .from('lead_interactions')
            .insert({
                lead_id: leadId,
                ...formData,
                next_action_date: formData.next_action_date || null, // Garantir null se vazio
                created_by: user.id,
                created_at: new Date().toISOString()
            })

        if (error) {
            console.error('Error creating interaction:', error)
            toast.error('Erro ao criar interação')
        } else {
            toast.success('Interação registrada!')
            setShowForm(false)
            setFormData({
                type: 'call',
                title: '',
                description: '',
                outcome: '',
                next_action: '',
                next_action_date: ''
            })
            loadInteractions()
        }
        setIsSubmitting(false)
    }

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-gray-400">
                <div className="w-8 h-8 border-2 border-primary border-t-transparent rounded-full animate-spin mb-4"></div>
                <p>Carregando histórico...</p>
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between pb-4 border-b border-gray-100 dark:border-white/5">
                <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
                    <History size={20} className="text-primary" />
                    Histórico de Interações
                </h3>
                <button
                    onClick={() => setShowForm(!showForm)}
                    className={`h-10 px-4 rounded-xl font-medium transition-all flex items-center gap-2 shadow-sm ${showForm
                            ? 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-white/10 dark:text-gray-300'
                            : 'bg-primary text-white hover:bg-primary-dark hover:shadow-primary/25'
                        }`}
                >
                    {showForm ? <X size={16} /> : <Plus size={16} />}
                    {showForm ? 'Cancelar' : 'Nova Interação'}
                </button>
            </div>

            {/* Form */}
            {showForm && (
                <form onSubmit={handleSubmit} className="bg-white dark:bg-card-dark rounded-2xl border border-gray-100 dark:border-white/5 p-6 space-y-4 shadow-sm animate-in slide-in-from-top-4 duration-300">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Tipo *
                            </label>
                            <div className="relative">
                                <select
                                    value={formData.type}
                                    onChange={(e) => setFormData({ ...formData, type: e.target.value as any })}
                                    className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary appearance-none"
                                >
                                    {INTERACTION_TYPES.map((type) => (
                                        <option key={type.value} value={type.value}>
                                            {type.label}
                                        </option>
                                    ))}
                                </select>
                                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none">
                                    {/* Ícone do tipo selecionado */}
                                    {INTERACTION_TYPES.find(t => t.value === formData.type)?.icon({ size: 18, className: 'text-gray-500' })}
                                </div>
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Título *
                            </label>
                            <input
                                type="text"
                                value={formData.title}
                                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                                className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary"
                                placeholder="Ex: Primeira ligação"
                                required
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Descrição *
                        </label>
                        <textarea
                            value={formData.description}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            rows={3}
                            className="w-full px-4 py-3 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary resize-none"
                            placeholder="Detalhe a interação..."
                            required
                        />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Resultado
                            </label>
                            <input
                                type="text"
                                value={formData.outcome}
                                onChange={(e) => setFormData({ ...formData, outcome: e.target.value })}
                                className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary"
                                placeholder="Ex: Cliente interessado"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Próxima Ação
                            </label>
                            <input
                                type="text"
                                value={formData.next_action}
                                onChange={(e) => setFormData({ ...formData, next_action: e.target.value })}
                                className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary"
                                placeholder="Ex: Agendar visita"
                            />
                        </div>
                    </div>

                    {formData.next_action && (
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                Data da Próxima Ação
                            </label>
                            <input
                                type="datetime-local"
                                value={formData.next_action_date}
                                onChange={(e) => setFormData({ ...formData, next_action_date: e.target.value })}
                                className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary"
                            />
                        </div>
                    )}

                    <div className="flex gap-3 pt-4 border-t border-gray-100 dark:border-white/5">
                        <button
                            type="submit"
                            disabled={isSubmitting}
                            className="flex-1 h-12 bg-primary text-white rounded-xl font-medium hover:bg-primary-dark transition-colors disabled:opacity-50 flex items-center justify-center gap-2 shadow-lg"
                        >
                            {isSubmitting ? (
                                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                            ) : (
                                <Save size={20} />
                            )}
                            Registrar Interação
                        </button>
                        <button
                            type="button"
                            onClick={() => setShowForm(false)}
                            className="h-12 px-6 border border-gray-200 dark:border-white/10 rounded-xl font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5 transition-colors"
                        >
                            Cancelar
                        </button>
                    </div>
                </form>
            )}

            {/* Timeline */}
            <div className="space-y-4">
                {interactions.length === 0 ? (
                    <div className="text-center py-16 bg-white dark:bg-card-dark rounded-2xl border border-gray-100 dark:border-white/5 shadow-sm">
                        <Clock size={48} className="text-gray-300 dark:text-gray-600 mx-auto mb-4" />
                        <h4 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">Nenhuma interação registrada</h4>
                        <p className="text-gray-500 mb-6 max-w-sm mx-auto">Registre o primeiro contato para iniciar o histórico deste lead.</p>
                        <button
                            onClick={() => setShowForm(true)}
                            className="inline-flex items-center gap-2 h-12 px-6 bg-primary text-white rounded-xl font-medium hover:bg-primary-dark transition-colors shadow-lg hover:shadow-primary/25"
                        >
                            <Plus size={20} />
                            Primeira Interação
                        </button>
                    </div>
                ) : (
                    <div className="relative pt-2">
                        {/* Timeline Line */}
                        <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-gray-200 dark:bg-white/10" />

                        {interactions.map((interaction, index) => {
                            const typeConfig = INTERACTION_TYPES.find(t => t.value === interaction.type) || INTERACTION_TYPES[5]
                            const Icon = typeConfig.icon

                            return (
                                <div key={interaction.id} className="relative pl-16 pb-8 group">
                                    {/* Icon */}
                                    <div className={`absolute left-0 w-12 h-12 rounded-full ${typeConfig.bg} dark:bg-opacity-20 flex items-center justify-center border-4 border-white dark:border-background-dark z-10 shadow-sm`}>
                                        <Icon size={20} className={typeConfig.color} />
                                    </div>

                                    {/* Content */}
                                    <div className="bg-white dark:bg-card-dark rounded-xl border border-gray-100 dark:border-white/5 p-6 hover:shadow-md transition-shadow relative">
                                        {/* Seta indicativa */}
                                        <div className="absolute top-6 -left-2 w-4 h-4 bg-white dark:bg-card-dark border-b border-l border-gray-100 dark:border-white/5 transform rotate-45"></div>

                                        <div className="flex items-start justify-between mb-3 relative z-10">
                                            <div>
                                                <h4 className="font-bold text-gray-900 dark:text-white text-lg">{interaction.title}</h4>
                                                <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                                                    <span className="flex items-center gap-1">
                                                        <User size={12} />
                                                        {interaction.user?.name || 'Usuário'}
                                                    </span>
                                                    <span>•</span>
                                                    <span className="flex items-center gap-1">
                                                        <Clock size={12} />
                                                        {formatDistanceToNow(new Date(interaction.created_at), {
                                                            addSuffix: true,
                                                            locale: ptBR
                                                        })}
                                                    </span>
                                                    <span className="hidden sm:inline opacity-50">
                                                        ({format(new Date(interaction.created_at), 'dd/MM/yyyy HH:mm')})
                                                    </span>
                                                </div>
                                            </div>
                                            <span className={`px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wider ${typeConfig.bg} ${typeConfig.color} dark:bg-opacity-10 border ${typeConfig.borderColor} dark:border-opacity-20`}>
                                                {typeConfig.label}
                                            </span>
                                        </div>

                                        <p className="text-gray-700 dark:text-gray-300 text-sm mb-4 whitespace-pre-wrap leading-relaxed">
                                            {interaction.description}
                                        </p>

                                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                            {interaction.outcome && (
                                                <div className="bg-green-50 dark:bg-green-900/10 border border-green-200 dark:border-green-900/30 rounded-lg p-3">
                                                    <div className="flex items-center gap-2 text-xs font-bold text-green-700 dark:text-green-400 mb-1 uppercase tracking-wide">
                                                        <CheckCircle size={14} />
                                                        Resultado
                                                    </div>
                                                    <p className="text-sm text-green-800 dark:text-green-300 font-medium">{interaction.outcome}</p>
                                                </div>
                                            )}

                                            {interaction.next_action && (
                                                <div className="bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-900/30 rounded-lg p-3">
                                                    <div className="flex items-center gap-2 text-xs font-bold text-blue-700 dark:text-blue-400 mb-1 uppercase tracking-wide">
                                                        <Calendar size={14} />
                                                        Próxima Ação
                                                    </div>
                                                    <p className="text-sm text-blue-800 dark:text-blue-300 font-medium">{interaction.next_action}</p>
                                                    {interaction.next_action_date && (
                                                        <p className="text-xs text-blue-600 dark:text-blue-400 mt-1 flex items-center gap-1">
                                                            <Clock size={10} />
                                                            {format(new Date(interaction.next_action_date), "dd 'de' MMM 'às' HH:mm", { locale: ptBR })}
                                                        </p>
                                                    )}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { X, Save, User, Mail, Phone, DollarSign, Building2, Tag, Calendar, UserPlus } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { toast } from 'sonner'

const supabase = createClient()

interface LeadFormData {
    name: string
    email: string
    phone: string
    status: string
    source: string
    interest: string
    capital: number | null
    development_id: string | null
    message: string
    assigned_to: string | null
    tags: string[]
}

const INITIAL_FORM_DATA: LeadFormData = {
    name: '',
    email: '',
    phone: '',
    status: 'new',
    source: 'website',
    interest: '',
    capital: null,
    development_id: null,
    message: '',
    assigned_to: null,
    tags: []
}

const SOURCES = [
    { value: 'website', label: 'Website' },
    { value: 'whatsapp', label: 'WhatsApp' },
    { value: 'phone', label: 'Telefone' },
    { value: 'email', label: 'E-mail' },
    { value: 'referral', label: 'Indicação' },
    { value: 'social', label: 'Redes Sociais' },
    { value: 'event', label: 'Evento' },
    { value: 'other', label: 'Outro' }
]

const INTERESTS = [
    { value: 'apartment_2q', label: 'Apartamento 2Q' },
    { value: 'apartment_3q', label: 'Apartamento 3Q' },
    { value: 'apartment_4q', label: 'Apartamento 4Q+' },
    { value: 'house', label: 'Casa' },
    { value: 'commercial', label: 'Comercial' },
    { value: 'land', label: 'Terreno' },
    { value: 'investment', label: 'Investimento' },
    { value: 'other', label: 'Outro' }
]

const TAGS = [
    'Alto Padrão',
    'Primeira Compra',
    'Investidor',
    'Urgente',
    'FGTS',
    'Financiamento',
    'À Vista',
    'Permuta'
]

interface LeadFormModalProps {
    leadId?: string
    initialStatus?: string
    onClose: () => void
    onSuccess: () => void
}

export default function LeadFormModal({ leadId, initialStatus, onClose, onSuccess }: LeadFormModalProps) {
    const [formData, setFormData] = useState<LeadFormData>({
        ...INITIAL_FORM_DATA,
        status: initialStatus || 'new'
    })
    const [loading, setLoading] = useState(false)
    const [developments, setDevelopments] = useState<any[]>([])
    const [brokers, setBrokers] = useState<any[]>([])
    const [errors, setErrors] = useState<Record<string, string>>({})

    useEffect(() => {
        loadDependencies()
        if (leadId) {
            loadLead(leadId)
        }
    }, [leadId])

    const loadDependencies = async () => {
        // Carregar empreendimentos
        const { data: devs } = await supabase
            .from('developments')
            .select('id, name')
            .eq('status', 'published')
            .order('name')

        setDevelopments(devs || [])

        // Carregar corretores
        const { data: brokerData } = await supabase
            .from('brokers')
            .select('user_id, name')
            .eq('status', 'active')
            .order('name')

        setBrokers(brokerData || [])
    }

    const loadLead = async (id: string) => {
        setLoading(true)
        const { data, error } = await supabase
            .from('leads')
            .select('*')
            .eq('id', id)
            .single()

        if (error) {
            toast.error('Erro ao carregar lead')
            onClose()
            return
        }

        if (data) {
            setFormData({
                name: data.name || '',
                email: data.email || '',
                phone: data.phone || '',
                status: data.status || 'new',
                source: data.source || 'website',
                interest: data.interest || '',
                capital: data.capital || null,
                development_id: data.development_id || null,
                message: data.message || '',
                assigned_to: data.assigned_to || null,
                tags: data.tags || []
            })
        }

        setLoading(false)
    }

    const handleInputChange = (field: keyof LeadFormData, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }))
        if (errors[field]) {
            setErrors(prev => {
                const newErrors = { ...prev }
                delete newErrors[field]
                return newErrors
            })
        }
    }

    const toggleTag = (tag: string) => {
        setFormData(prev => ({
            ...prev,
            tags: prev.tags.includes(tag)
                ? prev.tags.filter(t => t !== tag)
                : [...prev.tags, tag]
        }))
    }

    const validate = (): boolean => {
        const newErrors: Record<string, string> = {}

        if (!formData.name.trim()) newErrors.name = 'Nome é obrigatório'

        if (!formData.email.trim()) {
            newErrors.email = 'E-mail é obrigatório'
        } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
            newErrors.email = 'E-mail inválido'
        }

        if (!formData.phone.trim()) {
            newErrors.phone = 'Telefone é obrigatório'
        }

        setErrors(newErrors)
        return Object.keys(newErrors).length === 0
    }

    const calculateScore = (): number => {
        let score = 50 // Base score

        // Capital disponível (+30 points)
        if (formData.capital) {
            if (formData.capital >= 1000000) score += 30
            else if (formData.capital >= 500000) score += 20
            else if (formData.capital >= 200000) score += 10
        }

        // Interesse específico (+10 points)
        if (formData.interest && formData.interest !== 'other') score += 10

        // Desenvolvimento específico (+10 points)
        if (formData.development_id) score += 10

        // Tags de qualidade
        if (formData.tags.includes('Alto Padrão')) score += 15
        if (formData.tags.includes('Urgente')) score += 10
        if (formData.tags.includes('À Vista')) score += 15

        return Math.min(100, score)
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!validate()) {
            toast.error('Por favor, corrija os erros no formulário')
            return
        }

        setLoading(true)

        try {
            const score = calculateScore()
            const dataToSave = {
                ...formData,
                score,
                updated_at: new Date().toISOString()
            }

            if (leadId) {
                // Atualizar
                const { error } = await supabase
                    .from('leads')
                    .update(dataToSave)
                    .eq('id', leadId)

                if (error) throw error
                toast.success('Lead atualizado com sucesso!')
            } else {
                // Criar
                const { error } = await supabase
                    .from('leads')
                    .insert({
                        ...dataToSave,
                        created_at: new Date().toISOString()
                    })

                if (error) throw error
                toast.success('Lead criado com sucesso!')
            }

            onSuccess()
        } catch (error: any) {
            console.error('Erro ao salvar lead:', error)
            toast.error(error.message || 'Erro ao salvar lead')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-card-dark rounded-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto animate-in zoom-in-95 duration-200">
                {/* Header */}
                <div className="sticky top-0 bg-white dark:bg-card-dark border-b border-gray-100 dark:border-white/5 px-6 py-4 flex items-center justify-between z-10">
                    <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
                        {leadId ? <User size={20} className="text-primary" /> : <UserPlus size={20} className="text-primary" />}
                        {leadId ? 'Editar Lead' : 'Novo Lead'}
                    </h3>
                    <button
                        onClick={onClose}
                        className="w-8 h-8 rounded-lg hover:bg-gray-100 dark:hover:bg-white/5 flex items-center justify-center text-gray-500"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    {/* Informações Básicas */}
                    <div>
                        <h4 className="font-bold text-gray-900 dark:text-white mb-4 flex items-center gap-2 border-b border-gray-100 dark:border-white/5 pb-2">
                            <User size={18} className="text-primary" />
                            Informações Básicas
                        </h4>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Nome Completo *
                                </label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => handleInputChange('name', e.target.value)}
                                    className={`w-full h-12 px-4 border bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary ${errors.name ? 'border-red-300 focus:ring-red-200' : 'border-gray-200 dark:border-white/10'
                                        }`}
                                    placeholder="João Silva"
                                />
                                {errors.name && <p className="mt-1 text-sm text-red-600">{errors.name}</p>}
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    E-mail *
                                </label>
                                <div className="relative">
                                    <Mail size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                                    <input
                                        type="email"
                                        value={formData.email}
                                        onChange={(e) => handleInputChange('email', e.target.value)}
                                        className={`w-full h-12 pl-12 pr-4 border bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary ${errors.email ? 'border-red-300 focus:ring-red-200' : 'border-gray-200 dark:border-white/10'
                                            }`}
                                        placeholder="joao@email.com"
                                    />
                                </div>
                                {errors.email && <p className="mt-1 text-sm text-red-600">{errors.email}</p>}
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Telefone *
                                </label>
                                <div className="relative">
                                    <Phone size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                                    <input
                                        type="tel"
                                        value={formData.phone}
                                        onChange={(e) => handleInputChange('phone', e.target.value)}
                                        className={`w-full h-12 pl-12 pr-4 border bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary ${errors.phone ? 'border-red-300 focus:ring-red-200' : 'border-gray-200 dark:border-white/10'
                                            }`}
                                        placeholder="(81) 99999-8888"
                                    />
                                </div>
                                {errors.phone && <p className="mt-1 text-sm text-red-600">{errors.phone}</p>}
                            </div>
                        </div>
                    </div>

                    {/* Qualificação */}
                    <div>
                        <h4 className="font-bold text-gray-900 dark:text-white mb-4 flex items-center gap-2 border-b border-gray-100 dark:border-white/5 pb-2">
                            <DollarSign size={18} className="text-green-600" />
                            Qualificação
                        </h4>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Capital Disponível
                                </label>
                                <div className="relative">
                                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">R$</span>
                                    <input
                                        type="number"
                                        value={formData.capital || ''}
                                        onChange={(e) => handleInputChange('capital', e.target.value ? parseFloat(e.target.value) : null)}
                                        className="w-full h-12 pl-10 pr-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary"
                                        placeholder="500000"
                                        step="1000"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Interesse
                                </label>
                                <select
                                    value={formData.interest}
                                    onChange={(e) => handleInputChange('interest', e.target.value)}
                                    className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary appearance-none"
                                >
                                    <option value="">Selecione...</option>
                                    {INTERESTS.map((interest) => (
                                        <option key={interest.value} value={interest.value}>
                                            {interest.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Empreendimento
                                </label>
                                <select
                                    value={formData.development_id || ''}
                                    onChange={(e) => handleInputChange('development_id', e.target.value || null)}
                                    className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary appearance-none"
                                >
                                    <option value="">Nenhum específico</option>
                                    {developments.map((dev) => (
                                        <option key={dev.id} value={dev.id}>
                                            {dev.name}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                                    Origem
                                </label>
                                <select
                                    value={formData.source}
                                    onChange={(e) => handleInputChange('source', e.target.value)}
                                    className="w-full h-12 px-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary appearance-none"
                                >
                                    {SOURCES.map((source) => (
                                        <option key={source.value} value={source.value}>
                                            {source.label}
                                        </option>
                                    ))}
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* Tags */}
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2">
                            <Tag size={16} className="text-primary" />
                            Tags
                        </label>
                        <div className="flex flex-wrap gap-2">
                            {TAGS.map((tag) => (
                                <button
                                    key={tag}
                                    type="button"
                                    onClick={() => toggleTag(tag)}
                                    className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all border ${formData.tags.includes(tag)
                                            ? 'bg-primary text-white border-primary'
                                            : 'bg-gray-50 dark:bg-white/5 text-gray-700 dark:text-gray-300 border-gray-200 dark:border-white/10 hover:border-primary/50'
                                        }`}
                                >
                                    {tag}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Atribuição */}
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Atribuir a Corretor
                        </label>
                        <div className="relative">
                            <Building2 size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                            <select
                                value={formData.assigned_to || ''}
                                onChange={(e) => handleInputChange('assigned_to', e.target.value || null)}
                                className="w-full h-12 pl-12 pr-4 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary appearance-none"
                            >
                                <option value="">Não atribuído</option>
                                {brokers.map((broker) => (
                                    <option key={broker.user_id} value={broker.user_id}>
                                        {broker.name}
                                    </option>
                                ))}
                            </select>
                        </div>
                    </div>

                    {/* Mensagem */}
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                            Mensagem / Observações
                        </label>
                        <textarea
                            value={formData.message}
                            onChange={(e) => handleInputChange('message', e.target.value)}
                            rows={4}
                            className="w-full px-4 py-3 border border-gray-200 dark:border-white/10 bg-gray-50 dark:bg-input-dark dark:text-white rounded-xl focus:outline-none focus:ring-2 focus:ring-primary resize-none"
                            placeholder="Observações sobre o lead..."
                        />
                    </div>

                    {/* Score Preview */}
                    <div className="bg-purple-50 dark:bg-purple-900/10 border border-purple-100 dark:border-purple-900/30 rounded-xl p-4">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-purple-700 dark:text-purple-400">
                                Score Estimado:
                            </span>
                            <span className="text-2xl font-black text-purple-700 dark:text-purple-400">
                                {calculateScore()}
                            </span>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3 pt-6 border-t border-gray-100 dark:border-white/5">
                        <button
                            type="submit"
                            disabled={loading}
                            className="flex-1 h-12 bg-primary text-white rounded-xl font-medium hover:bg-primary-dark transition-colors disabled:opacity-50 flex items-center justify-center gap-2 shadow-lg hover:shadow-primary/25"
                        >
                            {loading ? (
                                <>
                                    <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                                    Salvando...
                                </>
                            ) : (
                                <>
                                    <Save size={20} />
                                    {leadId ? 'Atualizar' : 'Criar'} Lead
                                </>
                            )}
                        </button>
                        <button
                            type="button"
                            onClick={onClose}
                            className="h-12 px-8 border border-gray-200 dark:border-white/10 rounded-xl font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5 transition-colors"
                        >
                            Cancelar
                        </button>
                    </div>
                </form>
            </div>
        </div>
    )
}

