'use client'

import { useState, useEffect } from 'react'
import { Search, Filter, X } from 'lucide-react'
import Input from '@/components/ui/Input'
import Select from '@/components/ui/Select'
import Button from '@/components/ui/Button'
import { PropertyFilterParams as PropertyFilterParamsType } from '../types'
import { createClient } from '@/lib/supabase/client'

interface PropertyFiltersProps {
    filters: PropertyFilterParamsType
    onFiltersChange: (filters: PropertyFilterParamsType) => void
    onClear: () => void
}

export default function PropertyFilters({ filters, onFiltersChange, onClear }: PropertyFiltersProps) {
    const supabase = createClient()
    const [developers, setDevelopers] = useState<Array<{ id: string; name: string }>>([])
    const [neighborhoods, setNeighborhoods] = useState<string[]>([])
    const [isExpanded, setIsExpanded] = useState(false)

    useEffect(() => {
        fetchFilterOptions()
    }, [])

    async function fetchFilterOptions() {
        // Buscar construtoras
        const { data: devs } = await supabase
            .from('developers')
            .select('id, name')
            .eq('active', true)
            .order('name')

        if (devs) setDevelopers(devs)

        // Buscar bairros únicos
        const { data: props } = await supabase
            .from('developments')
            .select('neighborhood')

        if (props) {
            const uniqueNeighborhoods = Array.from(new Set(props.map(p => p.neighborhood).filter(Boolean)))
            setNeighborhoods(uniqueNeighborhoods.sort())
        }
    }

    const hasActiveFilters =
        filters.search ||
        (filters.status && filters.status !== 'all') ||
        (filters.type && filters.type !== 'all') ||
        (filters.developer_id && filters.developer_id !== 'all') ||
        (filters.neighborhood && filters.neighborhood !== 'all') ||
        filters.price_min ||
        filters.price_max ||
        (filters.bedrooms && filters.bedrooms !== 'all')

    return (
        <div className="bg-white rounded-xl p-6 border border-slate-200 mb-6">
            <div className="flex items-center gap-4 mb-4">
                <div className="flex-1">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                        <input
                            type="text"
                            placeholder="Buscar por nome, descrição ou bairro..."
                            value={filters.search || ''}
                            onChange={(e) => onFiltersChange({ ...filters, search: e.target.value })}
                            className="w-full h-11 pl-10 pr-4 rounded-lg border border-slate-200 focus:outline-none focus:ring-2 focus:ring-imi-500"
                        />
                    </div>
                </div>

                <Button
                    variant={isExpanded ? 'primary' : 'outline'}
                    onClick={() => setIsExpanded(!isExpanded)}
                >
                    <Filter className="w-4 h-4 mr-2" />
                    Filtros
                </Button>

                {hasActiveFilters && (
                    <Button variant="outline" onClick={onClear}>
                        <X className="w-4 h-4 mr-2" />
                        Limpar
                    </Button>
                )}
            </div>

            {isExpanded && (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 pt-4 border-t border-slate-200">
                    <Select
                        label="Status"
                        value={filters.status || 'all'}
                        onChange={(e) => onFiltersChange({ ...filters, status: e.target.value as any })}
                        options={[
                            { value: 'all', label: 'Todos' },
                            { value: 'active', label: 'Ativo' },
                            { value: 'inactive', label: 'Inativo' },
                            { value: 'pending', label: 'Pendente' },
                            { value: 'sold', label: 'Vendido' },
                        ]}
                    />

                    <Select
                        label="Tipo"
                        value={filters.type || 'all'}
                        onChange={(e) => onFiltersChange({ ...filters, type: e.target.value as any })}
                        options={[
                            { value: 'all', label: 'Todos' },
                            { value: 'apartment', label: 'Apartamento' },
                            { value: 'house', label: 'Casa' },
                            { value: 'penthouse', label: 'Cobertura' },
                            { value: 'studio', label: 'Studio' },
                            { value: 'land', label: 'Terreno' },
                        ]}
                    />

                    <Select
                        label="Construtora"
                        value={filters.developer_id || 'all'}
                        onChange={(e) => onFiltersChange({ ...filters, developer_id: e.target.value })}
                        options={[
                            { value: 'all', label: 'Todas' },
                            ...developers.map(dev => ({ value: dev.id, label: dev.name }))
                        ]}
                    />

                    <Select
                        label="Bairro"
                        value={filters.neighborhood || 'all'}
                        onChange={(e) => onFiltersChange({ ...filters, neighborhood: e.target.value })}
                        options={[
                            { value: 'all', label: 'Todos' },
                            ...neighborhoods.map(n => ({ value: n, label: n }))
                        ]}
                    />

                    <Input
                        label="Preço Mínimo"
                        type="number"
                        value={filters.price_min || ''}
                        onChange={(e) => onFiltersChange({ ...filters, price_min: e.target.value ? Number(e.target.value) : undefined })}
                        placeholder="R$ 0"
                    />

                    <Input
                        label="Preço Máximo"
                        type="number"
                        value={filters.price_max || ''}
                        onChange={(e) => onFiltersChange({ ...filters, price_max: e.target.value ? Number(e.target.value) : undefined })}
                        placeholder="R$ 0"
                    />

                    <Select
                        label="Quartos"
                        value={filters.bedrooms?.toString() || 'all'}
                        onChange={(e) => onFiltersChange({ ...filters, bedrooms: e.target.value === 'all' ? 'all' : Number(e.target.value) as any })}
                        options={[
                            { value: 'all', label: 'Todos' },
                            { value: '1', label: '1 quarto' },
                            { value: '2', label: '2 quartos' },
                            { value: '3', label: '3 quartos' },
                            { value: '4', label: '4+ quartos' },
                        ]}
                    />

                    <Select
                        label="Ordenar por"
                        value={filters.sort || 'recent'}
                        onChange={(e) => onFiltersChange({ ...filters, sort: e.target.value as any })}
                        options={[
                            { value: 'recent', label: 'Mais recentes' },
                            { value: 'name', label: 'Nome A-Z' },
                            { value: 'price_asc', label: 'Menor preço' },
                            { value: 'price_desc', label: 'Maior preço' },
                            { value: 'views', label: 'Mais visualizados' },
                        ]}
                    />
                </div>
            )}
        </div>
    )
}

'use client'

import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { Sparkles, Loader2 } from 'lucide-react'
import { propertySchema, PropertyFormData } from '../validations'
import { Property } from '../types'
import Input from '@/components/ui/Input'
import Textarea from '@/components/ui/Textarea'
import Select from '@/components/ui/Select'
import Button from '@/components/ui/Button'
import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase/client'
import MediaUploader from '@/components/ui/MediaUploader'

interface PropertyFormProps {
    property?: Property
    onSubmit: (data: PropertyFormData) => Promise<void>
    onCancel: () => void
    isSubmitting?: boolean
}

export default function PropertyForm({ property, onSubmit, onCancel, isSubmitting }: PropertyFormProps) {
    const supabase = createClient()
    const [developers, setDevelopers] = useState<Array<{ id: string; name: string }>>([])
    const [isGenerating, setIsGenerating] = useState(false)

    const {
        register,
        handleSubmit,
        formState: { errors },
        setValue,
        watch,
    } = useForm<PropertyFormData>({
        resolver: zodResolver(propertySchema) as any,
        defaultValues: property ? {
            name: property.name,
            slug: property.slug,
            description: property.description || '',
            developer_id: property.developer_id || '',
            type: property.type,
            status: property.status,
            address: property.address,
            neighborhood: property.neighborhood,
            city: property.city,
            state: property.state,
            zipcode: property.zipcode || '',
            price_from: property.price_from,
            price_to: property.price_to,
            bedrooms: property.bedrooms,
            bathrooms: property.bathrooms,
            parking_spaces: property.parking_spaces,
            area_from: property.area_from,
            area_to: property.area_to,
            units: property.units,
            floors: property.floors,
            delivery: property.delivery || null,
            launch_date: property.launch_date || null,
            featured: !!property.featured,
            image: property.image || '',
            gallery_images: property.gallery_images || [],
            floor_plans: property.floor_plans || [],
            country: property.country || 'Brasil',
            region: property.region || 'paraiba',
            status_commercial: property.status_commercial || 'draft',
            target_audience: property.target_audience || '',
        } : {
            status: 'active',
            status_commercial: 'draft',
            type: 'apartment',
            country: 'Brasil',
            region: 'paraiba',
            featured: false,
            units: 1,
            image: '',
            gallery_images: [],
            floor_plans: [],
        },
    })

    useEffect(() => {
        fetchDevelopers()
    }, [])

    async function fetchDevelopers() {
        const { data } = await supabase
            .from('developers')
            .select('id, name')
            .eq('active', true)
            .order('name')

        if (data) setDevelopers(data)
    }

    // Auto-gerar slug a partir do nome
    const name = watch('name')
    useEffect(() => {
        if (name && !property) {
            const slug = name
                .toLowerCase()
                .normalize('NFD')
                .replace(/[\u0300-\u036f]/g, '')
                .replace(/[^a-z0-9]+/g, '-')
                .replace(/(^-|-$)/g, '')
            setValue('slug', slug)
        }
    }, [name, property, setValue])

    async function handleGenerateAIDescription() {
        const values = watch()
        if (!values.name) {
            alert('Por favor, preencha o nome do empreendimento primeiro.')
            return
        }

        setIsGenerating(true)
        try {
            const response = await fetch('/api/ai/generate-description', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: values.name,
                    type: values.type,
                    neighborhood: values.neighborhood,
                    city: values.city,
                    features: [
                        values.bedrooms ? `${values.bedrooms} quartos` : '',
                        values.bathrooms ? `${values.bathrooms} banheiros` : '',
                        values.area_from ? `${values.area_from}m²` : '',
                    ].filter(Boolean)
                })
            })

            const data = await response.json()
            if (data.description) {
                setValue('description', data.description)
            }
        } catch (err) {
            console.error('IA Description fail:', err)
        } finally {
            setIsGenerating(false)
        }
    }

    return (
        <form onSubmit={handleSubmit((data) => onSubmit(data as unknown as PropertyFormData))} className="space-y-8">
            {/* Informações Básicas */}
            <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
                <h3 className="text-sm font-bold text-imi-900 uppercase tracking-widest mb-6">Informações Básicas</h3>
                <div className="grid md:grid-cols-2 gap-6">
                    <Input
                        label="Nome do Empreendimento *"
                        {...register('name')}
                        error={errors.name?.message}
                    />

                    <Input
                        label="Slug (URL amigável) *"
                        {...register('slug')}
                        error={errors.slug?.message}
                    />

                    <Select
                        label="Construtora *"
                        {...register('developer_id')}
                        error={errors.developer_id?.message}
                        options={[
                            { value: '', label: 'Selecione...' },
                            ...developers.map(dev => ({ value: dev.id, label: dev.name }))
                        ]}
                    />

                    <Select
                        label="Tipo *"
                        {...register('type')}
                        error={errors.type?.message}
                        options={[
                            { value: 'apartment', label: 'Apartamento' },
                            { value: 'house', label: 'Casa' },
                            { value: 'penthouse', label: 'Cobertura' },
                            { value: 'studio', label: 'Studio' },
                            { value: 'land', label: 'Terreno' },
                            { value: 'commercial', label: 'Comercial' },
                            { value: 'resort', label: 'Resort/Hotel' },
                        ]}
                    />

                    <Select
                        label="Status Interno *"
                        {...register('status')}
                        error={errors.status?.message}
                        options={[
                            { value: 'active', label: 'Ativo' },
                            { value: 'inactive', label: 'Inativo' },
                            { value: 'pending', label: 'Pendente' },
                            { value: 'sold', label: 'Vendido' },
                        ]}
                    />

                    <Select
                        label="Status Comercial (Site) *"
                        {...register('status_commercial')}
                        error={errors.status_commercial?.message}
                        options={[
                            { value: 'draft', label: 'Rascunho (Oculto)' },
                            { value: 'published', label: 'Publicado' },
                            { value: 'campaign', label: 'Em Campanha' },
                            { value: 'private', label: 'Venda Privada' },
                            { value: 'sold', label: 'Vendido' },
                        ]}
                    />

                    <div className="md:col-span-2 space-y-2">
                        <div className="flex items-center justify-between">
                            <label className="text-sm font-bold text-imi-900 uppercase tracking-widest">Descrição *</label>
                            <button
                                type="button"
                                onClick={handleGenerateAIDescription}
                                disabled={isGenerating}
                                className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-accent-600 hover:text-accent-700 transition-colors bg-accent-50 px-3 py-1.5 rounded-lg border border-accent-100"
                            >
                                {isGenerating ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                                Gerar via Inteligência IA
                            </button>
                        </div>
                        <Textarea
                            {...register('description')}
                            error={errors.description?.message}
                            rows={6}
                        />
                    </div>
                </div>
            </div>

            {/* Localização */}
            <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
                <h3 className="text-sm font-bold text-imi-900 uppercase tracking-widest mb-6">Localização</h3>
                <div className="grid md:grid-cols-2 gap-6">
                    <div className="md:col-span-2">
                        <Input
                            label="Endereço *"
                            {...register('address')}
                            error={errors.address?.message}
                        />
                    </div>

                    <Input
                        label="Bairro *"
                        {...register('neighborhood')}
                        error={errors.neighborhood?.message}
                    />

                    <Input
                        label="Cidade *"
                        {...register('city')}
                        error={errors.city?.message}
                    />

                    <Input
                        label="Estado (UF) *"
                        {...register('state')}
                        error={errors.state?.message}
                        maxLength={2}
                        placeholder="PE"
                    />

                    <Input
                        label="País *"
                        {...register('country')}
                        error={errors.country?.message}
                        placeholder="Brasil"
                    />

                    <Select
                        label="Região Estratégica *"
                        {...register('region')}
                        error={errors.region?.message}
                        options={[
                            { value: 'paraiba', label: 'Paraíba' },
                            { value: 'pernambuco', label: 'Pernambuco' },
                            { value: 'sao-paulo', label: 'São Paulo' },
                            { value: 'dubai', label: 'Dubai (Internacional)' },
                            { value: 'usa', label: 'USA (Internacional)' },
                            { value: 'other', label: 'Outras Regiões' },
                        ]}
                    />

                    <Input
                        label="CEP"
                        {...register('zipcode')}
                        error={errors.zipcode?.message}
                        placeholder="00000-000"
                    />
                </div>
            </div>

            {/* Valores */}
            <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm">
                <h3 className="text-sm font-bold text-imi-900 uppercase tracking-widest mb-6">Valores</h3>
                <div className="grid md:grid-cols-2 gap-6">
                    <Input
                        label="Preço A Partir De *"
                        type="number"
                        step="0.01"
                        {...register('price_from', { valueAsNumber: true })}
                        error={errors.price_from?.message}
                        placeholder="500000"
                    />

                    <Input
                        label="Preço Até"
                        type="number"
                        step="0.01"
                        {...register('price_to', {
                            setValueAs: (v) => v === '' ? null : Number(v)
